@startuml
skinparam packageStyle folder

package "controller" {
  class User <<C>> #90EE90

  interface Controller <<I>> #D8BFD8 {
    + execute(args : json) : json
  }

  class Amount <<C>> #90EE90
  class TransferSend <<C>> 
  class Transfer <<C>> 

  note right of Factory::create(name:string):Controller\n<<Factory Method Pattern>>\nCreates controller instances based on name parameter

  factory Folder1 as view2 {
      card C_Amount_view <<Amount View Component>>#FFA54F{
          * display(amount: number)\n* update(value: string)\n}

      skinparam rectangleBackgroundColor WhiteSmoke

      [view] -[hidden]-> C_Amount_view
  }

  model Folder3 as user_model_folder {
        card C_User_Model <<User Model Class>>#ADD8E6{
            id:int;name:String;\nbalance:number;}

       skinparam rectangleBackgroundcolor LightBlue

     [model]-[hidden]->C_User_Model   
   } 

note bottom left:"MVC Architecture:\n- Models manage data/state\nViews handle presentation\nControllers process input/commands"\n

class Factory <<Creator Interface>> {
+ create(name : string) : Controller
}


